circuit_design.openqasm3_template:
OPENQASM 3.0;
include "stdgates.inc";
bit[4] c;
qubit[4] q;
h q[0];
cx q[0], q[1];
cx q[1], q[2];
cx q[2], q[3];
delay[{D}us] q[0];
delay[{D}us] q[1];
delay[{D}us] q[2];
delay[{D}us] q[3];
// reverse-bell to bring back to |0000>
cx q[2], q[3];
cx q[1], q[2];
cx q[0], q[1];
h q[0];
c = measure q;
